package com.example.deeplinkapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity

class DeepLinkHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        // This activity doesn't need a UI
        setContentView(R.layout.activity_deep_link_handler)

        val uri: Uri? = intent?.data

        uri?.let {
            handleDeepLink(it)
        } ?: run {
            Log.w("DeepLinkHandler", "No URI found in intent, launching MainActivity.")
            startActivity(Intent(this, MainActivity::class.java))
        }

        // Finish this activity immediately so it doesn't stay in the back stack
        finish()
    }

    private fun handleDeepLink(uri: Uri) {
        Log.d("DeepLinkHandler", "Handling deep link: $uri")

        val host = uri.host
        val pathSegments = uri.pathSegments

        when (host) {
            "profile" -> {
                if (pathSegments.isNotEmpty()) {
                    val profileId = pathSegments[0]
                    val intent = Intent(this, ProfileActivity::class.java).apply {
                        putExtra("profileId", profileId)
                        // Optional: Clear task and bring app to front if it's already running
                        // flags = Intent.FLAG_ACTIVITY_CLEAR_TASK or Intent.FLAG_ACTIVITY_NEW_TASK
                    }
                    startActivity(intent)
                } else {
                    Log.d("DeepLinkHandler", "Deep link myapp://profile with no ID. Launching generic ProfileActivity.")
                    startActivity(Intent(this, ProfileActivity::class.java))
                }
            }
            "payment" -> {
                if (pathSegments.isNotEmpty() && pathSegments[0] == "confirm") {
                    val intent = Intent(this, PaymentActivity::class.java).apply {
                        putExtra("action", "confirm")
                        // flags = Intent.FLAG_ACTIVITY_CLEAR_TASK or Intent.FLAG_ACTIVITY_NEW_TASK
                    }
                    startActivity(intent)
                } else {
                    Log.d("DeepLinkHandler", "Deep link myapp://payment with unknown path. Launching generic PaymentActivity.")
                    startActivity(Intent(this, PaymentActivity::class.java))
                }
            }
            // Add more cases for other deep link types (e.g., "settings", "product")
            else -> {
                Log.w("DeepLinkHandler", "Unknown deep link host: $host. Launching MainActivity.")
                startActivity(Intent(this, MainActivity::class.java))
            }
        }
    }
}

